from airflow.decorators import dag, task
from airflow.sensors.filesystem import FileSensor
from datetime import datetime, timedelta

@dag(
    schedule='@daily',
    start_date=datetime(2026, 1, 1),
    catchup=False,
    default_args={
        'owner': 'data-engineering',
        'retries': 3,
        'retry_delay': timedelta(minutes=5)
    },
    tags=['nordgrid', 'meters', 'production']
)
def nordgrid_meter_daily():

    wait = FileSensor(
        task_id='wait_for_meters',
        filepath='/data/incoming/meters_{{ ds_nodash }}.csv',
        mode='reschedule',
        timeout=7200
    )

    @task
    def extract(ds_nodash=None) -> dict:
        path = f'/data/incoming/meters_{ds_nodash}.csv'
        return {'path': path, 'rows': count_rows(path)}

    @task
    def validate(metadata: dict) -> str:
        if metadata['rows'] < 100_000:
            raise ValueError(f"Only {metadata['rows']} rows")
        return metadata['path']

    @task
    def load_silver(validated_path: str, ds_nodash=None):
        dest = f's3://nordgrid-silver/meters/{ds_nodash}/'
        copy_to_silver(validated_path, dest)

    metadata = extract()
    path = validate(metadata)
    wait >> metadata  # sensor must complete before extract
    load_silver(path)

nordgrid_meter_daily()

class NordGridSFTPOperator(BaseOperator):
    template_fields: Sequence[str] = ('file_pattern', 'remote_dir', 'local_dir')

    def __init__(self, *, file_pattern: str, **kwargs):
        super().__init__(**kwargs)
        self.file_pattern = file_pattern

    def execute(self, context):
        self.log.info(f"Downloading: {self.file_pattern}")

class NordGridLoggingMixin:
    def _log_start(self, context):
        self.log.info("Task starting", extra={
            'dag_id': context['dag'].dag_id,
            'task_id': self.task_id
        })

class NordGridSFTPOperator(NordGridLoggingMixin, BaseOperator):
    def execute(self, context):
        self._log_start(context)
        result = self._do_download(context)
        return result

