from airflow.timetables.base import DagRunInfo, DataInterval, Timetable
import pendulum

NORDIC_HOLIDAYS_2026 = {
    pendulum.date(2026, 1, 1),
    pendulum.date(2026, 6, 19),
    pendulum.date(2026, 12, 25),
}

class NordGridBusinessDayTimetable(Timetable):
    description = 'Runs on Nordic business days'

    def _is_business_day(self, dt):
        return dt.day_of_week < 5 and dt not in NORDIC_HOLIDAYS_2026

    def _next_business_day(self, dt):
        candidate = dt.add(days=1)
        while not self._is_business_day(candidate):
            candidate = candidate.add(days=1)
        return candidate

